 1→import { useState } from "react";
 2→import type { CriteriaNode, CriteriaTree } from "../api/types";
 3→
 4→interface RuleNodeViewProps {
 5→  node: CriteriaNode;
 6→  depth: number;
 7→}
 8→
 9→function RuleNodeView({ node, depth }: RuleNodeViewProps) {
10→  const isLeaf = !node.rules || node.rules.length === 0;
11→  const [expanded, setExpanded] = useState(depth < 2);
12→
13→  if (isLeaf) {
14→    return (
15→      <div className="ml-4 py-1.5 pl-3 border-l-2 border-slate-300 text-sm text-slate-700">
16→        <span className="text-xs font-mono text-slate-400 mr-2">
17→          {node.rule_id}
18→        </span>
19→        {node.rule_text}
20→      </div>
21→    );
22→  }
23→
24→  const isAnd = node.operator === "AND";
25→  const badgeColor = isAnd
26→    ? "bg-emerald-100 text-emerald-700 border-emerald-300"
27→    : "bg-orange-100 text-orange-700 border-orange-300";
28→
29→  return (
30→    <div className="ml-4 my-1">
31→      <button
32→        onClick={() => setExpanded(!expanded)}
33→        className="flex items-center gap-2 w-full text-left group py-1"
34→      >
35→        <span className="text-slate-400 text-xs w-4 flex-shrink-0">
36→          {expanded ? "\u25BE" : "\u25B8"}
37→        </span>
38→        <span
39→          className={`text-[10px] font-semibold uppercase px-1.5 py-0.5 rounded border ${badgeColor}`}
40→        >
41→          {node.operator}
42→        </span>
43→        <span className="text-xs font-mono text-slate-400 mr-1">
44→          {node.rule_id}
45→        </span>
46→        <span className="text-sm text-slate-800 group-hover:text-slate-600">
47→          {node.rule_text}
48→        </span>
49→      </button>
50→      {expanded && node.rules && (
51→        <div className="ml-2 border-l border-slate-200">
52→          {node.rules.map((child) => (
53→            <RuleNodeView key={child.rule_id} node={child} depth={depth + 1} />
54→          ))}
55→        </div>
56→      )}
57→    </div>
58→  );
59→}
