61→interface TreeViewerProps {
62→  tree: CriteriaTree;
63→}
64→
65→export function TreeViewer({ tree }: TreeViewerProps) {
66→  return (
67→    <div>
68→      <h2 className="text-lg font-semibold text-slate-900 mb-1">
69→        {tree.title}
70→      </h2>
71→      <p className="text-xs text-slate-500 mb-4">{tree.insurance_name}</p>
72→      <RuleNodeView node={tree.rules} depth={0} />
73→    </div>
74→  );
75→}
